import{_ as n,o as s,c as l,ag as t}from"./chunks/framework.ePeAWSvT.js";const u=JSON.parse('{"title":"Screen Policy: 자주 묻는 질문 (FAQ)","description":"","frontmatter":{},"headers":[],"relativePath":"자주묻는질문_Screen_Policy_Final.md","filePath":"자주묻는질문_Screen_Policy_Final.md"}'),r={name:"자주묻는질문_Screen_Policy_Final.md"};function i(o,a,e,h,d,p){return s(),l("div",null,[...a[0]||(a[0]=[t(`<h1 id="screen-policy-자주-묻는-질문-faq" tabindex="-1">Screen Policy: 자주 묻는 질문 (FAQ) <a class="header-anchor" href="#screen-policy-자주-묻는-질문-faq" aria-label="Permalink to &quot;Screen Policy: 자주 묻는 질문 (FAQ)&quot;">​</a></h1><h2 id="■-screen-meta" tabindex="-1">■ Screen Meta <a class="header-anchor" href="#■-screen-meta" aria-label="Permalink to &quot;■ Screen Meta&quot;">​</a></h2><ul><li><strong>SCREEN_NAME</strong>: 고객센터 &gt; 자주 묻는 질문</li><li><strong>화면 목적</strong>: 고객이 자주 묻는 질문과 답변을 카테고리별로 조회</li><li><strong>화면 형태</strong>: 단일 페이지 (카테고리 탭 + 아코디언 목록)</li><li><strong>진입 경로</strong>: GNB &gt; 고객센터 &gt; 자주 묻는 질문</li><li><strong>관련 화면</strong>: 고객상담 화면, 마이페이지 &gt; 문의내역 화면</li></ul><hr><h2 id="■-화면-구조" tabindex="-1">■ 화면 구조 <a class="header-anchor" href="#■-화면-구조" aria-label="Permalink to &quot;■ 화면 구조&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>고객센터 &gt; 자주 묻는 질문</span></span>
<span class="line"><span>  ├─ [좌측 사이드바] 고객센터 메뉴 네비게이션</span></span>
<span class="line"><span>  │     ├─ 이용 안내</span></span>
<span class="line"><span>  │     │     ├─ 자주 묻는 질문  ← 현재 페이지 (강조 표시)</span></span>
<span class="line"><span>  │     │     ├─ 자료실</span></span>
<span class="line"><span>  │     │     ├─ 오시는 길</span></span>
<span class="line"><span>  │     │     └─ 사이트 이용방법</span></span>
<span class="line"><span>  │     ├─ 배송 안내</span></span>
<span class="line"><span>  │     │     ├─ 배송비·운임표</span></span>
<span class="line"><span>  │     │     ├─ 묶음배송</span></span>
<span class="line"><span>  │     │     └─ 낮배송/밤배송</span></span>
<span class="line"><span>  │     ├─ 회사 소개</span></span>
<span class="line"><span>  │     │     ├─ 성원애드피아 Youtube</span></span>
<span class="line"><span>  │     │     └─ 특허 현황</span></span>
<span class="line"><span>  │     ├─ 실시간 성원톡</span></span>
<span class="line"><span>  │     ├─ 원격지원</span></span>
<span class="line"><span>  │     └─ 카카오톡 상담</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ├─ [카테고리 탭] 전체 필터링</span></span>
<span class="line"><span>  │     ├─ A/S</span></span>
<span class="line"><span>  │     ├─ 고객상담</span></span>
<span class="line"><span>  │     ├─ 제작</span></span>
<span class="line"><span>  │     ├─ 출고/배송</span></span>
<span class="line"><span>  │     ├─ 파일접수</span></span>
<span class="line"><span>  │     └─ 회계관련</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ├─ [검색 필드] 키워드 검색</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  └─ [FAQ 목록] 아코디언 형식</span></span>
<span class="line"><span>        ├─ Q. 질문 텍스트</span></span>
<span class="line"><span>        └─ A. 답변 텍스트 (펼침 시 노출)</span></span></code></pre></div><hr><h2 id="■-카테고리-탭-정책" tabindex="-1">■ 카테고리 탭 정책 <a class="header-anchor" href="#■-카테고리-탭-정책" aria-label="Permalink to &quot;■ 카테고리 탭 정책&quot;">​</a></h2><h3 id="탭-구성" tabindex="-1">[탭 구성] <a class="header-anchor" href="#탭-구성" aria-label="Permalink to &quot;[탭 구성]&quot;">​</a></h3><ul><li><strong>탭 항목</strong>: A/S / 고객상담 / 제작 / 출고/배송 / 파일접수 / 회계관련</li><li><strong>기본 선택</strong>: A/S (첫 번째 탭)</li><li><strong>탭 전환 시</strong>: 해당 카테고리에 속한 FAQ 목록만 노출, 검색어 초기화</li></ul><h3 id="탭-카운트-뱃지" tabindex="-1">[탭 카운트 뱃지] <a class="header-anchor" href="#탭-카운트-뱃지" aria-label="Permalink to &quot;[탭 카운트 뱃지]&quot;">​</a></h3><ul><li><strong>표시 조건</strong>: 검색어 입력 후 검색 실행 시, 해당 탭 내 검색 결과 수를 카운트 뱃지로 표시</li><li><strong>표시 형식</strong>: <code>A/S(0)</code>, <code>고객상담(2)</code> 형식</li><li><strong>기본 상태 (검색 전)</strong>: 카운트 뱃지 미표시</li><li><strong>검색 후 상태</strong>: 각 탭별 검색 결과 수 카운트 뱃지 표시</li><li><strong>UI 정책</strong>: 검색 결과가 있는 탭만 노출. 결과가 없는 탭은 화면에서 숨김 처리</li></ul><hr><h2 id="■-검색-정책" tabindex="-1">■ 검색 정책 <a class="header-anchor" href="#■-검색-정책" aria-label="Permalink to &quot;■ 검색 정책&quot;">​</a></h2><h3 id="검색-필드" tabindex="-1">[검색 필드] <a class="header-anchor" href="#검색-필드" aria-label="Permalink to &quot;[검색 필드]&quot;">​</a></h3><ul><li><strong>필수 여부</strong>: 선택</li><li><strong>입력 규칙</strong>: 텍스트 자유 입력</li><li><strong>Placeholder</strong>: &quot;제목 또는 내용을 입력해주세요&quot;</li><li><strong>검색 실행 시점</strong>: 돋보기 버튼 클릭 시 검색 실행</li><li><strong>검색 범위</strong>: 전체 카테고리에서 검색 후 결과 표시</li><li><strong>검색 후 탭 동작</strong>: <ul><li>전체 카테고리 검색 결과를 각 탭별로 분류하여 카운트 뱃지 표시</li><li>카테고리 탭 선택 시 해당 탭의 검색 결과 목록 표시</li></ul></li><li><strong>결과 없음 시</strong>: &quot;검색 결과가 없어요.&quot; 안내 문구 표시</li></ul><h3 id="검색-결과-초기화" tabindex="-1">[검색 결과 초기화] <a class="header-anchor" href="#검색-결과-초기화" aria-label="Permalink to &quot;[검색 결과 초기화]&quot;">​</a></h3><ul><li><strong>초기화 조건</strong>: 검색 필드 내용 삭제 후 재검색 또는 카테고리 탭 전환 시 검색어 초기화</li></ul><hr><h2 id="■-faq-목록-정책" tabindex="-1">■ FAQ 목록 정책 <a class="header-anchor" href="#■-faq-목록-정책" aria-label="Permalink to &quot;■ FAQ 목록 정책&quot;">​</a></h2><h3 id="아코디언-동작" tabindex="-1">[아코디언 동작] <a class="header-anchor" href="#아코디언-동작" aria-label="Permalink to &quot;[아코디언 동작]&quot;">​</a></h3><ul><li><strong>기본 상태</strong>: 모든 항목 닫힘 (답변 숨김)</li><li><strong>펼침 동작</strong>: 질문 클릭 시 답변 영역 펼침</li><li><strong>복수 펼침</strong>: 불가 — 다른 항목 클릭 시 이전에 펼쳐진 항목 자동 닫힘 (단일 펼침 방식)</li><li><strong>닫힘 동작</strong>: 펼쳐진 항목 재클릭 시 닫힘</li></ul><h3 id="q-질문-표시" tabindex="-1">[Q (질문) 표시] <a class="header-anchor" href="#q-질문-표시" aria-label="Permalink to &quot;[Q (질문) 표시]&quot;">​</a></h3><ul><li><strong>표시 항목</strong>: &quot;Q&quot; 레이블 + 질문 텍스트</li><li><strong>UI 정책</strong>: 항목 우측에 펼침/닫힘 화살표 아이콘 표시</li></ul><h3 id="a-답변-표시" tabindex="-1">[A (답변) 표시] <a class="header-anchor" href="#a-답변-표시" aria-label="Permalink to &quot;[A (답변) 표시]&quot;">​</a></h3><ul><li><strong>표시 항목</strong>: 답변 텍스트 (서식 포함 가능: 줄바꿈, 강조 등)</li><li><strong>노출 조건</strong>: 질문 클릭(펼침) 시에만 노출</li><li><strong>링크 포함</strong>: 답변 내 링크 클릭 시 해당 화면으로 이동 (예: 마이페이지 문의내역)</li></ul><h3 id="목록-정렬" tabindex="-1">[목록 정렬] <a class="header-anchor" href="#목록-정렬" aria-label="Permalink to &quot;[목록 정렬]&quot;">​</a></h3><ul><li><strong>정렬 기준</strong>: 현업 확인 필요</li><li><strong>페이징</strong>: 무한 스크롤</li></ul><hr><h2 id="■-좌측-사이드바-네비게이션-정책" tabindex="-1">■ 좌측 사이드바 네비게이션 정책 <a class="header-anchor" href="#■-좌측-사이드바-네비게이션-정책" aria-label="Permalink to &quot;■ 좌측 사이드바 네비게이션 정책&quot;">​</a></h2><h3 id="메뉴-구조" tabindex="-1">[메뉴 구조] <a class="header-anchor" href="#메뉴-구조" aria-label="Permalink to &quot;[메뉴 구조]&quot;">​</a></h3><ul><li><strong>대분류</strong>: 이용 안내 / 배송 안내 / 회사 소개</li><li><strong>소분류</strong>: 각 대분류 하위 메뉴 (위 화면 구조 참조)</li><li><strong>현재 페이지 강조</strong>: 현재 선택된 메뉴 활성화 표시 (예: &quot;자주 묻는 질문&quot; 강조)</li></ul><h3 id="독립-상담-채널-링크-회사-소개와-별도-그룹" tabindex="-1">[독립 상담 채널 링크] (회사 소개와 별도 그룹) <a class="header-anchor" href="#독립-상담-채널-링크-회사-소개와-별도-그룹" aria-label="Permalink to &quot;[독립 상담 채널 링크] (회사 소개와 별도 그룹)&quot;">​</a></h3><ul><li><strong>실시간 성원톡</strong>: 클릭 시 실시간 채팅 채널로 이동</li><li><strong>원격지원</strong>: 클릭 시 원격지원 화면으로 이동</li><li><strong>카카오톡 상담</strong>: 클릭 시 카카오톡 채널로 이동</li></ul><hr><h2 id="■-예외-상황" tabindex="-1">■ 예외 상황 <a class="header-anchor" href="#■-예외-상황" aria-label="Permalink to &quot;■ 예외 상황&quot;">​</a></h2><h3 id="검색-결과-없음" tabindex="-1">[검색 결과 없음] <a class="header-anchor" href="#검색-결과-없음" aria-label="Permalink to &quot;[검색 결과 없음]&quot;">​</a></h3><ul><li><strong>처리</strong>: &quot;검색 결과가 없어요.&quot; 안내 문구 표시</li><li><strong>표시 위치</strong>: FAQ 목록 영역 내 중앙 표시</li></ul><h3 id="카테고리-내-검색-결과-0건" tabindex="-1">[카테고리 내 검색 결과 0건] <a class="header-anchor" href="#카테고리-내-검색-결과-0건" aria-label="Permalink to &quot;[카테고리 내 검색 결과 0건]&quot;">​</a></h3><ul><li><strong>처리</strong>: 해당 탭 숨김 처리. 결과 있는 탭만 노출</li></ul><h3 id="네트워크-오류-시" tabindex="-1">[네트워크 오류 시] <a class="header-anchor" href="#네트워크-오류-시" aria-label="Permalink to &quot;[네트워크 오류 시]&quot;">​</a></h3><ul><li><strong>처리</strong>: 에러 메시지 표시 및 재시도 유도</li></ul><hr><h2 id="■-현업-확인-필요사항" tabindex="-1">■ 현업 확인 필요사항 <a class="header-anchor" href="#■-현업-확인-필요사항" aria-label="Permalink to &quot;■ 현업 확인 필요사항&quot;">​</a></h2><h3 id="q4-faq-목록-정렬-기준" tabindex="-1">Q4. FAQ 목록 정렬 기준 <a class="header-anchor" href="#q4-faq-목록-정렬-기준" aria-label="Permalink to &quot;Q4. FAQ 목록 정렬 기준&quot;">​</a></h3><ul><li><strong>현재 상태</strong>: 현업 확인 필요</li><li><strong>확인 필요 사항</strong>: <ol><li>등록일 내림차순 (최신 등록 순)</li><li>조회수 내림차순 (많이 본 순)</li><li>관리자 수동 정렬</li></ol></li></ul><h3 id="q8-faq-관리-주체-관리자-기능-범위" tabindex="-1">Q8. FAQ 관리 주체 (관리자 기능 범위) <a class="header-anchor" href="#q8-faq-관리-주체-관리자-기능-범위" aria-label="Permalink to &quot;Q8. FAQ 관리 주체 (관리자 기능 범위)&quot;">​</a></h3><ul><li><strong>현재 상태</strong>: 현업 확인 필요</li><li><strong>확인 필요 사항</strong>: <ul><li>FAQ 등록/수정/삭제 권한자 정의 필요</li><li>카테고리 추가/변경 가능 여부 정의 필요</li></ul></li></ul><hr><h2 id="■-확정된-정책-요약" tabindex="-1">■ 확정된 정책 요약 <a class="header-anchor" href="#■-확정된-정책-요약" aria-label="Permalink to &quot;■ 확정된 정책 요약&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Q번호</th><th>항목</th><th>확정 내용</th></tr></thead><tbody><tr><td>Q1</td><td>검색 실행 시점</td><td>돋보기 버튼 클릭 시 검색 실행</td></tr><tr><td>Q2</td><td>검색 범위</td><td>전체 카테고리 검색 후 탭별 결과 분류 표시</td></tr><tr><td>Q3</td><td>아코디언 복수 펼침</td><td>불가 — 단일 펼침 방식 (다른 항목 클릭 시 이전 항목 자동 닫힘)</td></tr><tr><td>Q4</td><td>FAQ 목록 정렬 기준</td><td>현업 확인 필요</td></tr><tr><td>Q5</td><td>페이징 방식</td><td>무한 스크롤</td></tr><tr><td>Q6</td><td>검색 결과 없음 문구</td><td>&quot;검색 결과가 없어요.&quot;</td></tr><tr><td>Q7</td><td>탭 카운트 뱃지</td><td>검색 후 각 탭별 검색 결과 수 표시. 기본 상태(검색 전)는 미표시</td></tr><tr><td>Q8</td><td>FAQ 관리 주체</td><td>현업 확인 필요</td></tr></tbody></table><hr><h2 id="■-필요-화면-목록" tabindex="-1">■ 필요 화면 목록 <a class="header-anchor" href="#■-필요-화면-목록" aria-label="Permalink to &quot;■ 필요 화면 목록&quot;">​</a></h2><p>현재 화면 플로우에서 필요하지만 정의되지 않은 화면:</p><ol><li><strong>마이페이지 &gt; 문의내역 화면</strong> - FAQ 답변 내 &quot;마이페이지를 통해 문의 남겨주세요&quot; 클릭 시 이동</li><li><strong>고객상담 화면</strong> - 좌측 사이드바 고객상담 메뉴 클릭 시 이동</li><li><strong>FAQ 관리 화면 (관리자)</strong> - FAQ 등록/수정/삭제 관리자 화면 (Q8 확인 후 범위 정의)</li><li><strong>실시간 성원톡 화면</strong> - 사이드바 &quot;실시간 성원톡&quot; 클릭 시 이동</li><li><strong>원격지원 화면</strong> - 사이드바 &quot;원격지원&quot; 클릭 시 이동</li></ol>`,55)])])}const g=n(r,[["render",i]]);export{u as __pageData,g as default};
